	// BridgeCalls cross-wires the RTP recv loops of two CallRunners on
	// THIS edge so each leg's inbound packets become the other leg's
	// outbound. Both legs MUST be on this same edge — caller (media-
	// server's Scheduler.BridgeCalls) is responsible for routing the
	// request to the edge that owns both calls. Returns NotFound when
	// either call is missing on this edge.
	BridgeCalls(context.Context, *EdgeBridgeCallsRequest) (*EdgeBridgeCallsResponse, error)
	// SetCallHold toggles the runner's hold flag for one call. On
	// hold=true: bridge-relay packet copy pauses (if bridge wired);
	// active sender starts pumping the pre-encoded MOH clip looped.
	// On hold=false: relay resumes, MOH active sender stops.
	SetCallHold(context.Context, *EdgeSetCallHoldRequest) (*EdgeSetCallHoldResponse, error)
